private struct MessengerChatsScreen: View {
    @State private var selected: MessengerChatThread? = nil
    private let threads = MessengerDemoData.threads

    var body: some View {
        NavigationStack {
            List(threads) { thread in
                Button { selected = thread } label: {
                    MessengerChatRow(thread: thread)
                }
                .buttonStyle(.plain)
                .listRowInsets(EdgeInsets(top: 8, leading: 16, bottom: 8, trailing: 16))
                .listRowSeparatorTint(MessengerTokens.msgDivider.opacity(0.5))
            }
            .listStyle(.plain)
            .navigationTitle("Chats")
            .toolbar {
                ToolbarItem(placement: .topBarTrailing) {
                    Button {} label: { Image(systemName: "square.and.pencil") }
                }
            }
            .navigationDestination(item: $selected) { thread in
                MessengerChatDetailScreen(thread: thread)
            }
        }
    }
}

private struct MessengerChatRow: View {
    let thread: MessengerChatThread
    var body: some View {
        HStack(spacing: 12) {
            Circle()
                .fill(thread.avatarColor.gradient)
                .frame(width: 48, height: 48)
                .overlay(Text(thread.initials).font(.system(size: 18, weight: .semibold)).foregroundStyle(.white))
                .overlay(Circle().strokeBorder(MessengerTokens.msgActiveGreen, lineWidth: thread.unread > 0 ? 2.5 : 0))
            VStack(alignment: .leading, spacing: 4) {
                HStack {
                    Text(thread.name).font(MessengerFonts.msgMessageBody).foregroundStyle(MessengerTokens.msgTextPrimary)
                    Spacer()
                    Text(thread.time).font(.system(size: 12)).foregroundStyle(MessengerTokens.msgTextSecondary)
                }
                HStack {
                    Text(thread.preview).font(.system(size: 15)).foregroundStyle(MessengerTokens.msgTextSecondary).lineLimit(1)
                    Spacer()
                    if thread.unread > 0 {
                        Text("\(thread.unread)").font(.system(size: 12, weight: .semibold)).foregroundStyle(.white)
                            .padding(.horizontal, 7).padding(.vertical, 3)
                            .background(Capsule().fill(MessengerTokens.msgActiveGreen))
                    }
                }
            }
        }
        .frame(height: 56)
    }
}

private struct MessengerChatDetailScreen: View {
    let thread: MessengerChatThread
    @State private var draft = ""
    var body: some View {
        VStack(spacing: 0) {
            ScrollView {
                VStack(spacing: 8) {
                    MessengerSystemBanner(text: "Messages are end-to-end encrypted.")
                    ForEach(thread.messages) { msg in
                        if msg.outgoing {
                            MessengerOutgoingBubble(text: msg.text, time: msg.time, accent: MessengerTokens.msgGradBlue, textColor: MessengerTokens.msgTextPrimary, readColor: MessengerTokens.msgGradBlue)
                        } else {
                            MessengerIncomingBubble(text: msg.text, time: msg.time, fill: MessengerTokens.msgIncoming, textColor: MessengerTokens.msgTextPrimary)
                        }
                    }
                }
                .padding(.vertical, 12)
            }
            .background(MessengerTokens.msgGradBlue)
            MessengerComposeBar(text: $draft, accent: MessengerTokens.msgActiveGreen)
        }
        .navigationTitle(thread.name)
        .navigationBarTitleDisplayMode(.inline)
    }
}

