private struct MessengerChatThread: Identifiable, Hashable {
    let id = UUID()
    let name: String
    let initials: String
    let preview: String
    let time: String
    let unread: Int
    let avatarColor: Color
    let messages: [MessengerChatMessage]
}

private struct MessengerChatMessage: Identifiable, Hashable {
    let id = UUID()
    let text: String
    let time: String
    let outgoing: Bool
}

